@module routingManager  src=routingManager.lua  loc=813  sha=e848a59  mode=chunk

# Invariants & contracts
  @invariant  id is a track/fx GUID string — opaque to callers, stable across reload
  @invariant  stateless but for the scratch track it owns (guid in projext); re-read per call
  @invariant  non-native record fields are metadata; rm persists them (see docs/routingManager.md)

# Shapes
  @shape  fx = { id=guid, ident=string, name=string, ins=int, outs=int, inNames={str,...}, outNames={str,...}, pinMaps={ins={[port]={pair,...}}, outs=...}, midi={inBus,outBus,outDisabled} }  -- midi nil for JS; rm:fx adds trackId
  @shape  send = { to=guid, kind='audio'|'midi', gain=number, srcChan=int, dstChan=int, pos='preFx'|'preFader'|'postFader' }  -- track output routing; no id

